import{_ as e,o as r,c as o,ag as i}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Copyright & Intellectual Property","description":"","frontmatter":{},"headers":[],"relativePath":"theory/social/copyright.md","filePath":"theory/social/copyright.md"}'),a={name:"theory/social/copyright.md"};function n(s,t,d,l,c,h){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="copyright-intellectual-property" tabindex="-1">Copyright &amp; Intellectual Property <a class="header-anchor" href="#copyright-intellectual-property" aria-label="Permalink to &quot;Copyright &amp; Intellectual Property&quot;">​</a></h1><p>When you write code, design a logo, or compose a song, you&#39;ve created something. Copyright law protects that creation — and using someone else&#39;s work without permission has legal consequences. In IT, where content is freely copyable, understanding intellectual property is essential.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Copyright, licence agreements, and Creative Commons are introduced in Grade 10. Cybercrime legislation extends into Grade 11 and 12.</p></div><hr><h2 id="intellectual-property-ip" tabindex="-1">Intellectual Property (IP) <a class="header-anchor" href="#intellectual-property-ip" aria-label="Permalink to &quot;Intellectual Property (IP)&quot;">​</a></h2><p><strong>Intellectual property</strong> is a creation of the mind — an invention, design, piece of writing, software, music, or artwork — that is owned by its creator and protected by law.</p><p>Types of IP protection:</p><table tabindex="0"><thead><tr><th>Type</th><th>Protects</th><th>Duration</th></tr></thead><tbody><tr><td><strong>Copyright</strong></td><td>Creative works (music, art, code, writing)</td><td>Life of creator + 50–70 years</td></tr><tr><td><strong>Patent</strong></td><td>Inventions, technical processes</td><td>20 years</td></tr><tr><td><strong>Trademark</strong></td><td>Logos, brand names, symbols</td><td>Renewable indefinitely</td></tr><tr><td><strong>Trade secret</strong></td><td>Confidential business information</td><td>Indefinitely (while secret)</td></tr></tbody></table><hr><h2 id="copyright" tabindex="-1">Copyright <a class="header-anchor" href="#copyright" aria-label="Permalink to &quot;Copyright&quot;">​</a></h2><p><strong>Copyright</strong> automatically protects an original creative work from the moment it is created — no registration required. The copyright symbol © indicates protected work, but is not mandatory.</p><h3 id="what-copyright-protects" tabindex="-1">What copyright protects <a class="header-anchor" href="#what-copyright-protects" aria-label="Permalink to &quot;What copyright protects&quot;">​</a></h3><ul><li>Written works: books, articles, code, scripts</li><li>Music and sound recordings</li><li>Films and video</li><li>Artwork, photographs, and graphics</li><li>Software programs</li><li>Websites and online content</li></ul><h3 id="what-copyright-gives-the-owner" tabindex="-1">What copyright gives the owner <a class="header-anchor" href="#what-copyright-gives-the-owner" aria-label="Permalink to &quot;What copyright gives the owner&quot;">​</a></h3><p>The copyright owner has the <strong>exclusive right to</strong>:</p><ul><li>Copy and distribute the work</li><li>Modify or create derivative works</li><li>Perform or display the work</li><li>Sell or license the work to others</li></ul><h3 id="what-copyright-does-not-protect" tabindex="-1">What copyright does NOT protect <a class="header-anchor" href="#what-copyright-does-not-protect" aria-label="Permalink to &quot;What copyright does NOT protect&quot;">​</a></h3><ul><li>Ideas, concepts, and facts (only the expression of them)</li><li>Works in the public domain (copyright expired)</li><li>Works donated to the public domain by the creator</li></ul><hr><h2 id="licence-agreements" tabindex="-1">Licence Agreements <a class="header-anchor" href="#licence-agreements" aria-label="Permalink to &quot;Licence Agreements&quot;">​</a></h2><p>A <strong>software licence agreement</strong> (EULA — End User Licence Agreement) is the legal contract between the software developer and the user, specifying how the software may be used.</p><p><strong>You do not own purchased software — you licence the right to use it.</strong></p><table tabindex="0"><thead><tr><th>Licence Type</th><th>Cost</th><th>Modify source?</th><th>Distribute?</th><th>Example</th></tr></thead><tbody><tr><td><strong>Proprietary / Commercial</strong></td><td>Paid</td><td>No</td><td>No — cannot copy</td><td>Microsoft Office, Adobe Photoshop</td></tr><tr><td><strong>Freeware</strong></td><td>Free</td><td>No</td><td>Usually yes (as-is)</td><td>VLC, 7-Zip (some versions)</td></tr><tr><td><strong>Shareware</strong></td><td>Free trial</td><td>No</td><td>Share trial version</td><td>WinZip (trial period)</td></tr><tr><td><strong>Open source</strong></td><td>Usually free</td><td>Yes</td><td>Yes, under conditions</td><td>Linux, Firefox, LibreOffice</td></tr><tr><td><strong>Public domain</strong></td><td>Free</td><td>Yes</td><td>Yes, no restrictions</td><td>Some old government works</td></tr></tbody></table><hr><h2 id="creative-commons-cc" tabindex="-1">Creative Commons (CC) <a class="header-anchor" href="#creative-commons-cc" aria-label="Permalink to &quot;Creative Commons (CC)&quot;">​</a></h2><p><strong>Creative Commons</strong> provides a set of standard licences that allow creators to share their work with specific conditions — without others needing to ask permission for each use.</p><p>The creator chooses which rights to retain and which to grant:</p><table tabindex="0"><thead><tr><th>Symbol</th><th>Term</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>BY</strong></td><td>Attribution</td><td>Must credit the original creator</td></tr><tr><td><strong>SA</strong></td><td>Share-Alike</td><td>Derivative works must use the same licence</td></tr><tr><td><strong>NC</strong></td><td>Non-Commercial</td><td>Cannot use for commercial purposes</td></tr><tr><td><strong>ND</strong></td><td>No Derivatives</td><td>Cannot modify or remix the work</td></tr></tbody></table><p><strong>Common CC licence combinations:</strong></p><table tabindex="0"><thead><tr><th>Licence</th><th>Code</th><th>What it allows</th></tr></thead><tbody><tr><td>CC BY</td><td>Attribution only</td><td>Free to use, modify, share — must credit</td></tr><tr><td>CC BY-SA</td><td>Attribution + Share-Alike</td><td>Use and modify — but must share under same licence</td></tr><tr><td>CC BY-NC</td><td>Attribution + Non-Commercial</td><td>Use for non-commercial purposes only</td></tr><tr><td>CC BY-NC-ND</td><td>Most restrictive CC</td><td>Credit only — no commercial use, no modifications</td></tr><tr><td>CC0</td><td>Public domain dedication</td><td>Completely free — no conditions</td></tr></tbody></table><hr><h2 id="piracy" tabindex="-1">Piracy <a class="header-anchor" href="#piracy" aria-label="Permalink to &quot;Piracy&quot;">​</a></h2><p><strong>Software piracy</strong> is the illegal copying, distribution, or use of software without authorisation.</p><p><strong>Types of piracy:</strong></p><ul><li><strong>End-user piracy</strong>: Installing software on more computers than the licence allows</li><li><strong>Counterfeiting</strong>: Producing and selling fake copies of commercial software</li><li><strong>Internet piracy</strong>: Downloading or distributing software via torrent sites, etc.</li><li><strong>Hard disk loading</strong>: Pre-installing unlicensed software on computers being sold</li><li><strong>OEM abuse</strong>: Using OEM software outside its intended distribution channel</li></ul><p><strong>Consequences of piracy:</strong></p><table tabindex="0"><thead><tr><th>For the individual</th><th>For the organisation</th></tr></thead><tbody><tr><td>Criminal charges (fines, imprisonment)</td><td>Substantial corporate fines</td></tr><tr><td>Civil lawsuit by software company</td><td>Reputational damage</td></tr><tr><td>Malware risk (pirated software often contains viruses)</td><td>Loss of business licence</td></tr></tbody></table><hr><h2 id="plagiarism" tabindex="-1">Plagiarism <a class="header-anchor" href="#plagiarism" aria-label="Permalink to &quot;Plagiarism&quot;">​</a></h2><p><strong>Plagiarism</strong> is presenting someone else&#39;s work — writing, code, ideas — as your own without attribution.</p><ul><li>Copying a classmate&#39;s code without credit</li><li>Submitting someone else&#39;s essay as your own</li><li>Using online content without referencing the source</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">Plagiarism vs Copyright Infringement</p><p>Plagiarism is an ethical/academic offence (taking credit for others&#39; work). Copyright infringement is a legal offence (using protected work without permission). Both can occur simultaneously — e.g. copying a published article without credit or permission.</p></div><hr><h2 id="digital-rights-management-drm" tabindex="-1">Digital Rights Management (DRM) <a class="header-anchor" href="#digital-rights-management-drm" aria-label="Permalink to &quot;Digital Rights Management (DRM)&quot;">​</a></h2><p><strong>DRM</strong> is technology used to control how digital content (music, film, e-books, software) is used, copied, and distributed.</p><ul><li>Prevents unauthorised copying</li><li>Limits number of devices content can be played on</li><li>May require online activation</li></ul><p><strong>Examples:</strong> iTunes purchases (historically), Kindle books, Netflix streaming</p><p><strong>Controversy:</strong> DRM frustrates legitimate users but is often easily defeated by pirates.</p><hr><h2 id="south-african-legislation" tabindex="-1">South African Legislation <a class="header-anchor" href="#south-african-legislation" aria-label="Permalink to &quot;South African Legislation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Act</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Copyright Act (98 of 1978)</strong></td><td>Protects original creative works</td></tr><tr><td><strong>Electronic Communications and Transactions Act (ECT Act, 2002)</strong></td><td>Covers cybercrime, electronic contracts, digital signatures</td></tr><tr><td><strong>POPIA (Protection of Personal Information Act, 2013)</strong></td><td>Protects personal data from misuse</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Copyright</strong></td><td>Automatic legal protection of original creative work</td></tr><tr><td><strong>Intellectual property</strong></td><td>Creations of the mind protected by law</td></tr><tr><td><strong>EULA</strong></td><td>End User Licence Agreement — terms of software use</td></tr><tr><td><strong>Freeware</strong></td><td>Free-to-use software (source code not necessarily open)</td></tr><tr><td><strong>Open source</strong></td><td>Software with publicly available, modifiable source code</td></tr><tr><td><strong>Creative Commons</strong></td><td>Standardised licences for sharing creative works</td></tr><tr><td><strong>Piracy</strong></td><td>Illegal copying or distribution of protected software</td></tr><tr><td><strong>Plagiarism</strong></td><td>Presenting others&#39; work as your own</td></tr><tr><td><strong>DRM</strong></td><td>Digital Rights Management — technology restricting content use</td></tr><tr><td><strong>Public domain</strong></td><td>Works with no copyright restrictions (expired or waived)</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is software piracy? Give ONE consequence.&quot;</strong> — illegal copying of software; fines, criminal charges, malware risk</p></li><li><p><strong>&quot;Explain the difference between freeware and open source software&quot;</strong> — freeware = free to use, closed source; open source = source code available, can modify</p></li><li><p><strong>&quot;Describe TWO Creative Commons licence components&quot;</strong> — BY (attribution), SA (share-alike), NC (non-commercial), ND (no derivatives) — always explain what each means</p></li><li><p><strong>&quot;Give TWO rights that copyright gives the creator&quot;</strong> — exclusive right to copy, distribute, modify, sell, or licence the work</p></li><li><p><strong>&quot;What is an EULA?&quot;</strong> — End User Licence Agreement; legal contract specifying how software may be used; you licence the right to use, not own the software</p></li></ol></div>',57)])])}const u=e(a,[["render",n]]);export{p as __pageData,u as default};
